async function handlePostAuth(session) {
  const { data: profile, error } = await supabase.from('profiles').select('role, onboarding_complete').eq('id', session.user.id).single();
  if (error || !profile || !profile.onboarding_complete) {
    window.location.href = '/onboarding/role';
    return;
  }
  window.location.href = profile.role === 'landlord' ? '/listings' : '/search';
}
